import{_ as t,c as i,o as a,ag as o}from"./chunks/framework.IQH0tUiJ.js";const g=JSON.parse('{"title":"WebUI Directives","description":"","frontmatter":{},"headers":[],"relativePath":"guide/concepts/directives/index.md","filePath":"guide/concepts/directives/index.md"}'),r={name:"guide/concepts/directives/index.md"};function s(n,e,c,l,d,p){return a(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="webui-directives" tabindex="-1">WebUI Directives <a class="header-anchor" href="#webui-directives" aria-label="Permalink to &quot;WebUI Directives&quot;">​</a></h1><p>WebUI Framework offers several directives that allow you to create dynamic templates without JavaScript. These directives are processed during rendering to produce the final HTML output.</p><h2 id="available-directives" tabindex="-1">Available Directives <a class="header-anchor" href="#available-directives" aria-label="Permalink to &quot;Available Directives&quot;">​</a></h2><p>WebUI Framework provides the following core directives:</p><ul><li><a href="./if.html"><strong><code>&lt;if&gt;</code> Conditional Rendering</strong></a> - Conditionally render content based on expressions</li><li><a href="./for.html"><strong><code>&lt;for&gt;</code> Loop Iteration</strong></a> - Iterate over collections to generate repeated content</li><li><a href="./route.html"><strong><code>&lt;route&gt;</code> Routing</strong></a> - Define client-side routes that map URL paths to components</li><li><a href="./signals.html"><strong><code>{{}}</code> Signal Binding</strong></a> - Insert dynamic values with automatic HTML escaping</li><li><a href="./signals.html#raw-signals"><strong><code>{{{}}}</code> Raw Signal Binding</strong></a> - Insert unescaped HTML content</li><li><a href="./attributes.html"><strong>Attribute Directives</strong></a> - Bind dynamic data to HTML attributes (<code>{{}}</code>, <code>?</code>, <code>:</code>, and mixed)</li></ul><h2 id="how-directives-work" tabindex="-1">How Directives Work <a class="header-anchor" href="#how-directives-work" aria-label="Permalink to &quot;How Directives Work&quot;">​</a></h2><p>WebUI directives are processed by the WebUI parser and transformed into a platform-agnostic protocol. This protocol is then rendered by a language-specific handler, allowing the same template to be rendered consistently across multiple platforms.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Template with directives → WebUI Protocol → Native HTML output</span></span></code></pre></div><p>The WebUI protocol is a protobuf binary structure defined by a cross-language .proto schema, making it ideal for cross-platform applications.</p>',9)])])}const u=t(r,[["render",s]]);export{g as __pageData,u as default};
